{
  "claims": [
    {
      "id": "1",
      "claim": "Multiple systems treat context as a structured, governed layer rather than raw text dumps: IdeaBlocks bundle governance metadata with knowledge units, while markdown-based agent scaffolding routes files through a Harness rather than dumping them into prompts.",
      "theme": "Memory & context",
      "citations": [
        { "case_id": "6fd03526", "unit_id": "u-001-bc5f8608", "quote": "Instead of embedding a window of prose, you embed a claim: one question, its validated answer, and governance fields as typed schema." },
        { "case_id": "6fd03526", "unit_id": "u-018-54b228e8", "quote": "Each block receives typed metadata: clearance level (PUBLIC, INTERNAL, CONFIDENTIAL, SECRET), version state (Current, Deprecated, Draft, Approved), product line, export control flags, and data privacy labels." },
        { "case_id": "727a61c0", "unit_id": "u-004-d1340048", "quote": ".md 应该通过 Harness route 进入 context，不能直接倒进 prompt。" },
        { "case_id": "727a61c0", "unit_id": "u-011-4f4ddf0d", "quote": "AGENTS.md 在 model turn 组装前加载。它进入 stable workspace instruction context，和 project rules、local operating constraints 放在一起。" }
      ],
      "caveat": "Case 727a61c0 and 6fd03526 describe different substrate types (markdown scaffolding vs. RAG preprocessing), but both share the principle of governing context entry."
    },
    {
      "id": "2",
      "claim": "Naive approaches that treat chunks or transcripts as neutral containers tend to strip away the context and metadata needed for reliable retrieval and access control.",
      "theme": "Memory & context",
      "citations": [
        { "case_id": "6fd03526", "unit_id": "u-003-bcff0b13", "quote": "Every RAG pipeline starts with the same assumption: a chunk of text is the right unit of knowledge to embed." },
        { "case_id": "6fd03526", "unit_id": "u-004-c822efaf", "quote": "A chunk of text is a structurally neutral container." },
        { "case_id": "6fd03526", "unit_id": "u-005-05fce334", "quote": "You end up retrieving half a table, or a conclusion with no argument, or a claim stripped of the context that makes it true." },
        { "case_id": "6fd03526", "unit_id": "u-007-394a6e17", "quote": "Because the chunk carries no metadata either, there's nowhere to attach access control in the data itself." },
        { "case_id": "727a61c0", "unit_id": "u-002-3e14d41a", "quote": "旧 notes 会和当前 instructions 竞争" },
        { "case_id": "727a61c0", "unit_id": "u-003-b13a9aa6", "quote": "Model 得到了更多 text，但 task 得到的有用的 instruction 更少。" },
        { "case_id": "c038f472", "unit_id": "u-002-c9de8c0e", "quote": "Most memory systems don't do this. They learn instantly, the moment data flows in, and then never look at it again." }
      ],
      "caveat": "Case c038f472 describes single-pass summarization rather than chunking, but identifies the same underlying failure mode: premature commitment to what matters."
    },
    {
      "id": "3",
      "claim": "Better-performing systems use progressive disclosure to load context at the right time rather than flooding the context window, and they allow earlier information to be reweighted in light of new evidence.",
      "theme": "Memory & context",
      "citations": [
        { "case_id": "727a61c0", "unit_id": "u-016-7dda2cf7", "quote": "它使用 progressive disclosure。" },
        { "case_id": "727a61c0", "unit_id": "u-017-83b07a9f", "quote": "SKILL.md 先以 capability metadata 出现，task invoke 之后才加载 body。它进入 task procedure context：steps、tool expectations、checks、output shape。" },
        { "case_id": "727a61c0", "unit_id": "u-012-aac3dfa4", "quote": "它能提升某类 task 的表现，是因为它在正确时机给 model 一个聚焦的 procedure。" },
        { "case_id": "c038f472", "unit_id": "u-006-17c0bc51", "quote": "It DEFINITELY shouldn't be a hash table you write once and read forever (like other memory providers). It should think about what it knows, on its own, in the background, and get better at remembering you the longer it lives." },
        { "case_id": "c038f472", "unit_id": "u-008-f0c70091", "quote": "And the part that matters most: it reweights old facts in light of everything that's come in since they were written." },
        { "case_id": "c038f472", "unit_id": "u-010-67a0d372", "quote": "It's three things at once: new memories, a graph of inferences (we also call them derivations) that weave between them, and a weighted, evolving picture of who the user actually is." }
      ],
      "caveat": "Progressive disclosure timing differs: Case 727a61c0 uses task-triggered loading while Case c038f472 uses background heuristics; both reject fixed, up-front dumps but solve it differently."
    },
    {
      "id": "4",
      "claim": "The goal of reducing corpus size while preserving signal appears in both RAG preprocessing and memory systems: fewer but better-grounded entries outperform dense, redundant collections.",
      "theme": "Memory & context",
      "citations": [
        { "case_id": "6fd03526", "unit_id": "u-011-fe3712e9", "quote": "Word count dropped from 88,877 to 44,537" },
        { "case_id": "6fd03526", "unit_id": "u-012-7cf251c7", "quote": "The reason redundant copies hurt rather than help: fifteen near-duplicates of the same paragraph create fifteen competing vectors in the same region of embedding space." },
        { "case_id": "6fd03526", "unit_id": "u-013-0931a113", "quote": "Your vector index isn't a hard drive you want to fill." },
        { "case_id": "c038f472", "unit_id": "u-009-1767d088", "quote": "Memories that were too confident get tempered. Memories that contradicted each other get resolved. Memories that were just sitting there, isolated, suddenly find their neighbors." },
        { "case_id": "c038f472", "unit_id": "u-011-432b50a1", "quote": "They came in over months, across dozens of separate conversations, in no particular order. Dreaming is what stitched them into a single thought." }
      ],
      "caveat": "Case 6fd03526 targets structural deduplication via cosine similarity; Case c038f472 targets semantic reweighting. Both reduce redundancy but at different layers (ingestion vs. reflection)."
    },
    {
      "id": "5",
      "claim": "Case 727a61c0 and Case c038f472 both describe the same failure mode where early summarization locks in a premature conclusion and later evidence cannot correct it.",
      "theme": "Memory & context",
      "citations": [
        { "case_id": "727a61c0", "unit_id": "u-002-3e14d41a", "quote": "旧 notes 会和当前 instructions 竞争" },
        { "case_id": "c038f472", "unit_id": "u-004-1e9a83bb", "quote": "A user spends twenty minutes debating two architectures and lands on option B in the very last message, but the system already wrote down \"prefers option A\" from the middle of the discussion." },
        { "case_id": "c038f472", "unit_id": "u-005-307912d0", "quote": "Or what about the user who comes back tomorrow and asks about yesterday's conversation, only to find that the only thing left of it is a three-line summary that decided, prematurely and forever, what mattered?" }
      ],
      "caveat": "Single-source for this exact framing; Case 6fd03526 addresses redundancy rather than premature closure specifically."
    }
  ]
}
